var asm = Assembly.LoadFrom("/home/runner/.nuget/packages/modelcontextprotocol/0.2.0-preview.3/lib/net9.0/ModelContextProtocol.dll");

Console.WriteLine("=" + new string('=', 78));
Console.WriteLine("ATTRIBUTES IN ModelContextProtocol.Server NAMESPACE");
Console.WriteLine("=" + new string('=', 78));

var types = asm.GetTypes()
    .Where(t => t.Namespace == "ModelContextProtocol.Server" && t.Name.Contains("Attribute"))
    .OrderBy(t => t.Name);

foreach(var type in types)
{
    Console.WriteLine($"\n{type.FullName}");

    // Show constructors
    var ctors = type.GetConstructors();
    foreach(var ctor in ctors)
    {
        var pars = ctor.GetParameters();
        var parStr = string.Join(", ", pars.Select(p => $"{p.ParameterType.Name} {p.Name}"));
        Console.WriteLine($"  .ctor({parStr})");
    }

    // Show public properties
    var props = type.GetProperties(BindingFlags.Public | BindingFlags.Instance);
    foreach(var prop in props)
    {
        Console.WriteLine($"  {prop.PropertyType.Name} {prop.Name}");
    }
}

Console.WriteLine("\n" + new string('=', 80));
Console.WriteLine("TYPE DEFINITIONS (McpServer* and Resource* classes)");
Console.WriteLine("=" + new string('=', 80));

var otherTypes = asm.GetTypes()
    .Where(t => t.Namespace == "ModelContextProtocol.Server" && 
        (t.Name.StartsWith("McpServer") || t.Name.Contains("Resource") || t.Name.Contains("Prompt")))
    .OrderBy(t => t.Name);

foreach(var type in otherTypes)
{
    if(type.Name.Contains("Attribute")) continue;

    Console.WriteLine($"\n{type.FullName}");
    Console.WriteLine($"  IsInterface: {type.IsInterface}");
    Console.WriteLine($"  IsClass: {type.IsClass}");

    // Show constructors
    var ctors = type.GetConstructors(BindingFlags.Public | BindingFlags.Instance);
    foreach(var ctor in ctors.Take(3))
    {
        var pars = ctor.GetParameters();
        var parStr = string.Join(", ", pars.Select(p => $"{p.ParameterType.Name} {p.Name}"));
        Console.WriteLine($"  .ctor({parStr})");
    }
}
