import xml.etree.ElementTree as ET
import re

xml_file = "/home/runner/.nuget/packages/modelcontextprotocol/0.2.0-preview.3/lib/net9.0/ModelContextProtocol.xml"
tree = ET.parse(xml_file)
root = tree.getroot()

print("=" * 80)
print("API OVERVIEW - ALL TYPES AND METHODS")
print("=" * 80)

members = {}
for member in root.findall('.//member'):
    name = member.get('name', '')

    # Parse the member name to extract type info
    # Format: T:namespace.ClassName or M:namespace.ClassName.MethodName
    if name.startswith('T:'):
        typename = name[2:]  # Remove 'T:' prefix
        summary = member.findtext('summary', '')

        if 'ModelContextProtocol' in typename:
            members[typename] = {
                'type': 'Type',
                'summary': summary[:100] if summary else '',
            }
    elif name.startswith('M:'):
        method = name[2:]  # Remove 'M:' prefix
        if any(x in method for x in ['McpServer', 'AddMcpServer', 'WithTools', 'WithResources', 'MapMcp']):
            summary = member.findtext('summary', '')
            members[method] = {
                'type': 'Method',
                'summary': summary[:100] if summary else '',
            }

# Print organized
print("\nCLASSES/INTERFACES (ModelContextProtocol.Server):")
for name in sorted([k for k in members.keys() if k.startswith('ModelContextProtocol.Server') and '.' not in k.split('ModelContextProtocol.Server.')[-1]]):
    print(f"  {name.split('.')[-1]}")

print("\nMETHODS (Builder Extensions):")
for name in sorted([k for k in members.keys() if 'McpServerBuilderExtensions.With' in k]):
    method = name.split('.')[-1]
    # Extract method signature
    if '(' in method:
        method = method.split('(')[0]
    print(f"  .{method}(...)")

EOF

