cat > /tmp/extract_api.py << 'EOF'
import xml.etree.ElementTree as ET

xml_file = "/home/runner/.nuget/packages/modelcontextprotocol.core/0.2.0-preview.3/lib/net9.0/ModelContextProtocol.Core.xml"
tree = ET.parse(xml_file)
root = tree.getroot()

# Extract full summary text for a member
def get_full_summary(member):
    summary_elem = member.find('summary')
    if summary_elem is None:
        return ""

    text = ""
    for item in summary_elem.itertext():
        text += item
    return " ".join(text.split())

# Key classes/attributes
targets = {
    "McpServerToolAttribute": [],
    "McpServerToolTypeAttribute": [],
    "McpServerResourceAttribute": [],
    "McpServerResourceTypeAttribute": [],
    "McpServerPromptAttribute": [],
    "McpServerPromptTypeAttribute": [],
}

# Collect all members for each target
for member in root.findall('.//member'):
    name = member.get('name', '')

    for target in targets:
        if f'T:ModelContextProtocol.Server.{target}' == name:
            # This is the type definition
            summary = get_full_summary(member)
            targets[target].append({
                'type': 'Type',
                'name': name,
                'summary': summary[:200]
            })
        elif f'T:ModelContextProtocol.Server.{target}.' in name:
            # Properties/methods of this attribute
            member_type = 'M' if '.M:' in name else 'P'
            member_display = name.split('.')[-1]
            summary = get_full_summary(member)
            targets[target].append({
                'type': member_type,
                'name': member_display,
                'summary': summary[:100] if summary else '(no docs)'
            })

# Print results
for target, members in targets.items():
    if members:
        print(f"\n{'=' * 80}")
        print(f"{target}")
        print('=' * 80)

        type_info = [m for m in members if m['type'] == 'Type']
        if type_info:
            print(f"\nSummary: {type_info[0]['summary']}")

        props = [m for m in members if m['type'] == 'P']
        methods = [m for m in members if m['type'] == 'M']

        if props:
            print(f"\nProperties ({len(props)}):")
            for p in props[:5]:
                print(f"  - {p['name']}: {p['summary']}")

        if methods:
            print(f"\nMethods ({len(methods)}):")
            for m in methods[:5]:
                print(f"  - {m['name']}: {m['summary']}")

EOF

