### **Complete Usage Example**

```csharp
// Program.cs - Console App with Stdio Transport
[McpServerToolType]
public static class EchoTools
{
    [McpServerTool, Description("Echoes the message")]
    public static string Echo(string message) => $"Echo: {message}";
}

[McpServerResourceType]
public static class FileResources
{
    [McpServerResource(UriTemplate = "file://{path}")]
    public static string ReadFile(string path) 
        => System.IO.File.ReadAllText(path);
}

// Setup
var builder = Host.CreateApplicationBuilder(args);
builder.Services
    .AddMcpServer()
    .WithStdioServerTransport()
    .WithToolsFromAssembly()
    .WithResourcesFromAssembly();

await builder.Build().RunAsync();

// ---

// Program.cs - ASP.NET Core with HTTP Transport
var builder = WebApplication.CreateBuilder(args);
builder.Services
    .AddMcpServer()
    .WithHttpTransport(options =>
    {
        options.IdleTimeout = TimeSpan.FromHours(2);
        options.Stateless = false;
    })
    .WithToolsFromAssembly()
    .WithResourcesFromAssembly();

var app = builder.Build();
app.MapMcp("/mcp");  // Maps to /mcp/* endpoints
app.Run("http://localhost:3001");
```

---

This API surface covers all the key extension points for registering and configuring MCP servers using both attributes and programmatic approaches, supporting tools, resources, prompts, and multiple transport mechanisms.

